      subtitle: "\u041C\u043D\u043E\u0433\u043E\u0435 \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0442\u0441\u044F \u2014 \u0438 \u0435\u0441\u0442\u044C \u0433\u0434\u0435 \u043F\u0440\u0438\u0431\u0430\u0432\u0438\u0442\u044C",
      pain: "\u0413\u0434\u0435-\u0442\u043E \u0432\u0441\u0451 \u0438\u0434\u0451\u0442 \u0445\u043E\u0440\u043E\u0448\u043E, \u0433\u0434\u0435-\u0442\u043E \u0442\u0435\u0440\u044F\u0435\u0442\u0435 \u0432\u0440\u0435\u043C\u044F \u0438 \u0434\u0435\u043D\u044C\u0433\u0438 \u043D\u0430 \u0440\u0443\u0447\u043D\u043E\u0439 \u0440\u0430\u0431\u043E\u0442\u0435. \u042D\u0442\u043E \u043D\u043E\u0440\u043C\u0430\u043B\u044C\u043D\u043E. \u0417\u0430\u0434\u0430\u0447\u0430 \u043D\u0435 \u0441\u0442\u0430\u0442\u044C \u0438\u0434\u0435\u0430\u043B\u044C\u043D\u044B\u043C, \u0430 \u0443\u0431\u0440\u0430\u0442\u044C \u0441\u0430\u043C\u044B\u0435 \u0434\u043E\u0440\u043E\u0433\u0438\u0435 \u043F\u0440\u0438\u0432\u044B\u0447\u043A\u0438 \u0438 \u043D\u0435 \u043B\u043E\u043C\u0430\u0442\u044C\u0441\u044F \u043F\u043E\u0434 \u043D\u0430\u0433\u0440\u0443\u0437\u043A\u043E\u0439.",
      insight: "\u0427\u0430\u0441\u0442\u043E \u0432\u044B\u0438\u0433\u0440\u044B\u0432\u0430\u0435\u0442 \u043D\u0435 \u0441\u0430\u043C\u044B\u0439 \u0442\u0430\u043B\u0430\u043D\u0442\u043B\u0438\u0432\u044B\u0439, \u0430 \u0441\u0430\u043C\u044B\u0439 \u0441\u0442\u0430\u0431\u0438\u043B\u044C\u043D\u044B\u0439 \u043F\u043E \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0443.",
