      caseTitle: "\u041A\u0435\u0439\u0441, \u0431\u043B\u0438\u0437\u043A\u0438\u0439 \u0432\u0430\u0448\u0435\u043C\u0443 \u043F\u0440\u043E\u0444\u0438\u043B\u044E",
      caseText: "\u041F\u0440\u0435\u0434\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C \u0432 e-commerce \u0438\u0437 \u041A\u0430\u0437\u0430\u043D\u0438 \u043F\u043E\u0434\u043A\u043B\u044E\u0447\u0438\u043B \u0418\u0418 \u0442\u043E\u0447\u0435\u0447\u043D\u043E: \u043A\u0430\u0440\u0442\u043E\u0447\u043A\u0438 \u0442\u043E\u0432\u0430\u0440\u043E\u0432 \u0447\u0435\u0440\u0435\u0437 ChatGPT, \u0432\u0438\u0437\u0443\u0430\u043B \u0447\u0435\u0440\u0435\u0437 Midjourney. \u041A\u043E\u043D\u0432\u0435\u0440\u0441\u0438\u044F \u0432\u044B\u0440\u043E\u0441\u043B\u0430 \u043D\u0430 18%, \u0430 \u0432\u0440\u0435\u043C\u044F \u043D\u0430 \u043A\u043E\u043D\u0442\u0435\u043D\u0442 \u0441\u043E\u043A\u0440\u0430\u0442\u0438\u043B\u043E\u0441\u044C \u043D\u0430 10 \u0447\u0430\u0441\u043E\u0432 \u0432 \u043D\u0435\u0434\u0435\u043B\u044E.",
