      this.time = 100;
      this.energy = 100;
      this.missedIncome = 0;
      this.stats = {
        trapHits: 0,
        trapSwiped: 0,
        goodCaught: 0,
        goodMissed: 0,
        highValueCaught: 0,
        textCaught: 0,
        visualCaught: 0,
        structureCaught: 0,
        boosterCaught: 0,
        forkBold: 0,
        forkCaution: 0,
        forkMargin: 0,
        comboMax: 0,
        wavesCompleted: 0,
        overheatTriggers: 0,
        forkFollowupsResolved: 0,
        overloadSpawnPenalties: 0
      };
      this._goodCatchStreak = 0;
      this._lastGoodCatchMs = 0;
      this._raf = null;
      this._boundLoop = this.loop.bind(this);
      this.CATCHER_W = 90;
      this.CATCHER_H = 18;
      this.catcherX = 0;
      this.catcherEl = null;
      this._pointerId = null;
      this._dragLastFieldX = 0;
      this._holdLeft = false;
      this._holdRight = false;
      this.MOVE_PX_PER_SEC = 360;
      this._onPointerDown = this.onFieldPointerDown.bind(this);
      this._onPointerMove = this.onFieldPointerMove.bind(this);
      this._onPointerUp = this.onFieldPointerUp.bind(this);
      this._onDocPointerUp = this.onDocPointerUp.bind(this);
      this._onKeyDown = this.onKeyDown.bind(this);
      this._onKeyUp = this.onKeyUp.bind(this);
