      this.entities.clear();
      this.combo = 0;
      this.comboTier = 1;
      this.nextGoodMultiplier = 1;
      this.chaos = false;
      this.chaosBannerShown = false;
      this.forkPending = false;
      this.pauseMsTotal = 0;
      this._pauseWallStart = 0;
      this._forkFrozenElapsed = 0;
      this._lastHudWave = 0;
      this._pulseSlot = -1;
      this.money = 0;
      this.time = 100;
      this.energy = 100;
      this.missedIncome = 0;
      this.stats = {
        trapHits: 0,
        trapSwiped: 0,
        goodCaught: 0,
        goodMissed: 0,
        highValueCaught: 0,
        textCaught: 0,
        visualCaught: 0,
        structureCaught: 0,
        boosterCaught: 0,
        forkBold: 0,
        forkCaution: 0,
        forkMargin: 0,
        comboMax: 0,
        wavesCompleted: 0,
        overheatTriggers: 0,
        forkFollowupsResolved: 0,
        overloadSpawnPenalties: 0
      };
      this._goodCatchStreak = 0;
      this._lastGoodCatchMs = 0;
