      barTime: $("bar-time"),
      barEnergy: $("bar-energy"),
      statMoney: $("hud-stat-money"),
      statTime: $("hud-stat-time"),
      statEnergy: $("hud-stat-energy"),
      timer: $("hud-timer"),
      combo: $("hud-combo"),
      wave: $("hud-wave"),
